import json
import sys
from datetime import datetime

def validate_consent(data):
    reference_date = datetime.strptime(data["reference_date"], "%Y-%m-%d")
    activities = data["processing_activities"]
    consents = {c["purpose"]: c for c in data["user_consents"]}

    results = []
    counts = {"authorized": 0, "expired": 0, "denied": 0, "no_consent": 0}

    for activity in activities:
        purpose = activity["purpose"]
        consent = consents.get(purpose)

        if consent is None:
            results.append({
                "activity_id": activity["id"],
                "purpose": purpose,
                "status": "no_consent",
                "reason": "no consent record found"
            })
            counts["no_consent"] += 1
        elif not consent["granted"]:
            results.append({
                "activity_id": activity["id"],
                "purpose": purpose,
                "status": "denied",
                "reason": "consent explicitly denied"
            })
            counts["denied"] += 1
        elif consent["expires"] and datetime.strptime(consent["expires"], "%Y-%m-%d") < reference_date:
            results.append({
                "activity_id": activity["id"],
                "purpose": purpose,
                "status": "expired",
                "consent_expired": consent["expires"]
            })
            counts["expired"] += 1
        else:
            results.append({
                "activity_id": activity["id"],
                "purpose": purpose,
                "status": "authorized",
                "consent_valid_until": consent["expires"] if consent["expires"] else "indefinite"
            })
            counts["authorized"] += 1

    total = len(activities)
    compliance_rate = round(counts["authorized"] / total, 2) if total > 0 else 0

    result = {
        "results": results,
        "summary": {
            "authorized": counts["authorized"],
            "expired": counts["expired"],
            "denied": counts["denied"],
            "no_consent": counts["no_consent"],
            "compliance_rate": compliance_rate
        }
    }

    print(json.dumps(result, indent=2))

data = json.loads(sys.stdin.read())
validate_consent(data)
